{
  "decision": "驳回",
  "summary": "项目总评因关键规则R021、R024、R036未通过，且均为严重级失败，导致整体审批不通过。其中，业务全景图内容与管理模型内容过短，无法支撑审批决策；目标计划缺失完整时间范围，影响里程碑完整性。尽管项目内容部分、项目价值、预算信息及费用变化点等页面已通过，但关键基线规则的严重缺陷不可忽视，故最终结论为驳回。",
  "item_results": [
    {
      "rule_id": "R021",
      "status": "fail",
      "reason": "业务全景图内容过短，仅填写‘业务全景图标题’，无实质性内容，无法支撑审批决策。",
      "evidence": [
        "content:业务全景图标题"
      ],
      "suggestion": "请补充完整的业务全景图内容，明确系统间交互关系、流程节点或关键业务场景"
    },
    {
      "rule_id": "R024",
      "status": "fail",
      "reason": "管理模型内容过短，仅填写‘管理模型内容’，无实质说明，无法支撑审批决策。",
      "evidence": [
        "content:管理模型内容"
      ],
      "suggestion": "请补充详细的年度管理模型内容，包括责任分工、执行机制、考核方式等"
    },
    {
      "rule_id": "R036",
      "status": "fail",
      "reason": "目标计划缺少起止时间，未提供完整时间范围，无法确认目标达成时间节点。",
      "evidence": [
        "target_plan 字段为空，无 start 和 end 时间字段"
      ],
      "suggestion": "请补充目标计划的起止时间及具体目标内容，确保里程碑完整性"
    }
  ],
  "risks": [
    "业务全景图与管理模型内容缺失，导致项目实施路径与管控机制不清晰，存在执行风险。",
    "缺乏具体流程说明与职责划分，可能影响跨部门协同效率与项目交付质量。",
    "目标计划缺失可能导致项目进度失控，影响交付与验收"
  ],
  "missing_information": [
    "业务全景图内容（应包含系统/流程/角色间的交互逻辑）",
    "管理模型内容（应包含组织职责、流程机制、考核指标等）",
    "目标计划的开始时间（start）",
    "目标计划的结束时间（end）",
    "目标计划的具体目标或交付物说明"
  ]
}

